import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        if M!=0 and N % M == 0 and (N // M) % 2 == 0:
            out.append('Yes')
        else:
            out.append('No')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

